        public ProfileRating()
        {
            DefaultStyleKey = typeof(ProfileRating);
        }

        protected override void OnLoaded()
        {
            _fillBrush?.Register();
            _strokeBrush?.Register();
        }

        protected override void OnUnloaded()
        {
            _fillBrush?.Unregister();
            _strokeBrush?.Unregister();
        }

        protected override Size MeasureOverride(Size availableSize)
        {
            return Value != 0 ? new Size(24, 24) : new Size(0, 0);
        }

        #region Fill

        private CompositionColorSource _fillBrush;

        public Brush Fill
        {
            get { return (Brush)GetValue(FillProperty); }
            set { SetValue(FillProperty, value); }
        }

        public static readonly DependencyProperty FillProperty =
            DependencyProperty.Register("Fill", typeof(Brush), typeof(ProfileRating), new PropertyMetadata(null, OnFillChanged));

        private static void OnFillChanged(DependencyObject d, DependencyPropertyChangedEventArgs e)
        {
            ((ProfileRating)d).OnFillChanged(e.NewValue as SolidColorBrush, e.OldValue as SolidColorBrush);
        }

        private void OnFillChanged(SolidColorBrush newValue, SolidColorBrush oldValue)
        {
            _fillBrush?.PropertyChanged(newValue, IsConnected);
        }

        #endregion

        #region Stroke

        private CompositionColorSource _strokeBrush;

        public Brush Stroke
        {
            get { return (Brush)GetValue(StrokeProperty); }
            set { SetValue(StrokeProperty, value); }
        }

        public static readonly DependencyProperty StrokeProperty =
            DependencyProperty.Register("Stroke", typeof(Brush), typeof(ProfileRating), new PropertyMetadata(null, OnStrokeChanged));

        private static void OnStrokeChanged(DependencyObject d, DependencyPropertyChangedEventArgs e)
        {
            ((ProfileRating)d).OnStrokeChanged(e.NewValue as SolidColorBrush, e.OldValue as SolidColorBrush);
        }

        private void OnStrokeChanged(SolidColorBrush newValue, SolidColorBrush oldValue)
        {
            _strokeBrush?.PropertyChanged(newValue, IsConnected);
        }

        #endregion

        #region Value

        public int Value
        {
            get { return (int)GetValue(ValueProperty); }
            set { SetValue(ValueProperty, value); }
        }

        public static readonly DependencyProperty ValueProperty =
            DependencyProperty.Register("Value", typeof(int), typeof(ProfileRating), new PropertyMetadata(0, OnValueChanged));

        private static void OnValueChanged(DependencyObject d, DependencyPropertyChangedEventArgs e)
        {
            ((ProfileRating)d).OnValueChanged((int)e.NewValue, (int)e.OldValue);
        }

        private void OnValueChanged(int newValue, int oldValue)
        {
            var level = newValue < 0 ? _minusLevel : _levels.LastOrDefault(x => x.Number <= newValue);
            if (level == null)
            {
                ElementCompositionPreview.SetElementChildVisual(this, null);
                InvalidateMeasure();

                return;
            }

            var compositor = Window.Current.Compositor;
            var device = ElementComposition.GetSharedDevice();

            var outer = CompositionPathParser.Parse(level.OuterPath);
            var inner = CompositionPathParser.Parse(device, level.InnerPath);

            using var format = new CanvasTextFormat
            {
                FontSize = 28,
                FontFamily = "Segoe UI",
                FontWeight = FontWeights.SemiBold,
                HorizontalAlignment = CanvasHorizontalAlignment.Center,
                VerticalAlignment = CanvasVerticalAlignment.Center,
            };

            using var layout = new CanvasTextLayout(device, newValue < 0 ? "!" : newValue.ToString(), format, 72, 68);

            var text = CanvasGeometry.CreateText(layout);
            var group = inner.CombineWith(text, Matrix3x2.Identity, CanvasGeometryCombine.Xor);

            var outerShape = compositor.CreateSpriteShape(compositor.CreatePathGeometry(outer));
            outerShape.StrokeThickness = 0;
            outerShape.FillBrush = _strokeBrush ??= new CompositionColorSource(Stroke, IsConnected);

            var innerShape = compositor.CreateSpriteShape(compositor.CreatePathGeometry(new CompositionPath(group)));
            innerShape.StrokeThickness = 0;
            innerShape.FillBrush = _fillBrush ??= new CompositionColorSource(Fill, IsConnected);

            var visual = compositor.CreateShapeVisual();
            visual.Shapes.Add(outerShape);
            visual.Shapes.Add(innerShape);
            visual.RelativeSizeAdjustment = Vector2.One;
            visual.ViewBox = compositor.CreateViewBox();
            visual.ViewBox.Size = new Vector2(72, 72);
            visual.ViewBox.Stretch = CompositionStretch.Uniform;

            ElementCompositionPreview.SetElementChildVisual(this, visual);
            InvalidateMeasure();
        }

        #endregion
    }
